from collections import deque

def solution(graph, start):
    visited = []
    queue = deque([start])
    seen = {start}
    while queue:
        node = queue.popleft()
        visited.append(node)
        for neighbor in sorted(graph.get(node, [])):
            if neighbor not in seen:
                seen.add(neighbor)
                queue.append(neighbor)
    return visited

def solution(n):
    dp = [0] * (n + 1)
    if n >= 1:
        dp[1] = 1
    for i in range(2, n + 1):
        dp[i] = dp[i - 1] + dp[i - 2]
    return dp[n]

